# JWT Authentication Implementation Plan

## Context

The Express API currently has no authentication system. All write endpoints (POST/PUT/DELETE) are unprotected and default `userId` to `1`. The task requires adding JWT-based auth: registration, login, token-protected routes, and ownership enforcement. The `jsonwebtoken` package is already installed. Tests are pre-written in `tests/auth.test.ts` and define exact expected behavior.

---

## Working Directory

```
/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775270153773-g8auc2
```

---

## Critical Files

| File | Action |
|---|---|
| `src/routes/auth.ts` | **CREATE** – register + login endpoints |
| `src/middleware/auth.ts` | **CREATE** – JWT verification middleware |
| `src/routes/posts.ts` | **MODIFY** – add middleware + ownership checks |
| `src/routes/comments.ts` | **MODIFY** – add middleware + ownership checks |
| `src/app.ts` | **MODIFY** – wire auth router at `/auth` |
| `src/types.ts` | No changes needed |
| `src/db.ts` | No changes needed (seed users stay plaintext; tests only log in with freshly-registered users) |

---

## Implementation Steps

### Step 1 — Create `src/middleware/auth.ts`

Use **global Express namespace augmentation** so `req.user` is available everywhere without casting.

```typescript
import { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";

export const JWT_SECRET = "super-secret-key";

// Augment Express Request globally so req.user works in all route handlers
declare global {
  namespace Express {
    interface Request {
      user?: { id: number; username: string };
    }
  }
}

export function authenticateToken(req: Request, res: Response, next: NextFunction): void {
  const authHeader = req.headers["authorization"];
  const token = authHeader?.split(" ")[1]; // "Bearer <token>"

  if (!token) {
    res.status(401).json({ error: "Authentication required" });
    return;
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET) as { id: number; username: string };
    req.user = payload;
    next();
  } catch {
    res.status(401).json({ error: "Invalid token" });
  }
}
```

---

### Step 2 — Create `src/routes/auth.ts`

Password hashing: use Node built-in `crypto.createHash("sha256")` (no bcrypt).

```typescript
import { Router } from "express";
import { createHash } from "crypto";
import jwt from "jsonwebtoken";
import { users, nextId } from "../db.js";
import { JWT_SECRET } from "../middleware/auth.js";

const router = Router();

function hashPassword(password: string): string {
  return createHash("sha256").update(password).digest("hex");
}

// POST /auth/register
router.post("/register", (req, res) => {
  const { username, email, password } = req.body;
  if (!username || !email || !password) {
    res.status(400).json({ error: "username, email, and password are required" });
    return;
  }
  if (users.find((u) => u.username === username)) {
    res.status(409).json({ error: "Username already exists" });
    return;
  }
  const newUser = { id: nextId(users), username, email, password: hashPassword(password) };
  users.push(newUser);
  const token = jwt.sign({ id: newUser.id, username: newUser.username }, JWT_SECRET);
  res.status(201).json({
    token,
    user: { id: newUser.id, username: newUser.username, email: newUser.email },
  });
});

// POST /auth/login
router.post("/login", (req, res) => {
  const { username, password } = req.body;
  const user = users.find((u) => u.username === username);
  if (!user || user.password !== hashPassword(password)) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }
  const token = jwt.sign({ id: user.id, username: user.username }, JWT_SECRET);
  res.status(200).json({ token });
});

export { router as authRouter };
```

**Key details:**
- Returns `{ token, user: { id, username, email } }` on register (no `password` field) — matches test assertions
- Returns `{ token }` on login
- Duplicate username → 409; missing fields → 400; bad credentials → 401

---

### Step 3 — Modify `src/routes/posts.ts`

Add `authenticateToken` middleware to POST, PUT, DELETE. Use `req.user!.id` in POST. Check ownership in PUT and DELETE.

Changes to the existing route handlers:

**POST `/`** — add middleware, replace `userId: userId || 1` with `userId: req.user!.id`

**PUT `/:id`** — add middleware, after finding the post check `posts[index].userId !== req.user!.id` → 403

**DELETE `/:id`** — add middleware, after finding the post check `posts[index].userId !== req.user!.id` → 403

```typescript
// At top, add:
import { authenticateToken } from "../middleware/auth.js";

// POST /posts - now protected
router.post("/", authenticateToken, (req, res) => {
  const { title, content } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: req.user!.id,   // ← from token, not body
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id - now protected + ownership check
router.put("/:id", authenticateToken, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.id) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id - now protected + ownership check
router.delete("/:id", authenticateToken, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.id) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});
```

---

### Step 4 — Modify `src/routes/comments.ts`

Add `authenticateToken` to POST, PUT, DELETE. Use `req.user!.id` in POST. Add ownership check to DELETE.

```typescript
// At top, add:
import { authenticateToken } from "../middleware/auth.js";

// POST /posts/:postId/comments - now protected
router.post("/posts/:postId/comments", authenticateToken, (req, res) => {
  // ... existing post-not-found check ...
  const { body } = req.body;
  if (!body) { ... }
  const newComment: Comment = {
    id: nextId(comments),
    postId,
    userId: req.user!.id,   // ← from token, not body
    body,
    createdAt: new Date().toISOString(),
  };
  // ...
});

// PUT /comments/:id - now protected (no ownership test, but per spec)
router.put("/comments/:id", authenticateToken, (req, res) => { ... });

// DELETE /comments/:id - now protected + ownership check
router.delete("/comments/:id", authenticateToken, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = comments.findIndex((c) => c.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Comment not found" });
    return;
  }
  if (comments[index].userId !== req.user!.id) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const deleted = comments.splice(index, 1);
  res.json(deleted[0]);
});
