### Step 3 — Modify `src/routes/posts.ts`

Add `authenticateToken` middleware to POST, PUT, DELETE. Use `req.user!.id` in POST. Check ownership in PUT and DELETE.

Changes to the existing route handlers:

**POST `/`** — add middleware, replace `userId: userId || 1` with `userId: req.user!.id`

**PUT `/:id`** — add middleware, after finding the post check `posts[index].userId !== req.user!.id` → 403

**DELETE `/:id`** — add middleware, after finding the post check `posts[index].userId !== req.user!.id` → 403

```typescript
// At top, add:
import { authenticateToken } from "../middleware/auth.js";

// POST /posts - now protected
router.post("/", authenticateToken, (req, res) => {
  const { title, content } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: req.user!.id,   // ← from token, not body
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id - now protected + ownership check
router.put("/:id", authenticateToken, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.id) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id - now protected + ownership check
router.delete("/:id", authenticateToken, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.id) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});
```

